    66→function parseCSV(text: string): { headers: string[]; rows: string[][] } {
    67→  const lines = text.trim().split("\n").filter(Boolean);
    68→  if (lines.length === 0) return { headers: [], rows: [] };
    69→  const headers = lines[0].split(",").map(h => h.trim().replace(/^"|"$/g, "").toLowerCase());
    70→  const rows = lines.slice(1).map(l => l.split(",").map(c => c.trim().replace(/^"|"$/g, "")));
    71→  return { headers, rows };
    72→}
