   219→function DonutChart({ data, size = 88 }: { data: { style: string; count: number; pct: number }[]; size?: number }) {
   220→  const r = size * 0.36;
   221→  const strokeW = size * 0.15;
   222→  const gap = 1.5;
   223→  const cx = size / 2;
   224→  const cy = size / 2;
   225→  const circumference = 2 * Math.PI * r;
   226→
   227→  let offset = 0;
   228→  const slices = data.map(d => {
   229→    const dash = (d.pct / 100) * circumference - gap;
   230→    const slice = { ...d, dash, offset };
   231→    offset += (d.pct / 100) * circumference;
   232→    return slice;
   233→  });
   234→
   235→  return (
   236→    <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
   237→      {slices.map(s => {
   238→        const info = STYLE_INFO[s.style as StyleOption];
   239→        return (
   240→          <circle key={s.style} cx={cx} cy={cy} r={r}
   241→            fill="none"
   242→            stroke={info?.color ?? "#888"}
   243→            strokeWidth={strokeW}
   244→            strokeDasharray={`${s.dash} ${circumference - s.dash}`}
   245→            strokeDashoffset={-(s.offset) + circumference / 4}
   246→            style={{ transition: "stroke-dasharray 0.5s" }} />
   247→        );
   248→      })}
   249→    </svg>

