import { useLocation } from "wouter";
import { useAchievements } from "@/hooks/use-achievements";
import { ACHIEVEMENT_DEFS, ACHIEVEMENT_GROUPS, type AchievementGroup } from "@shared/achievements";
import { Button } from "@/components/ui/button";
import { ArrowLeft, Lock } from "lucide-react";
import { motion } from "framer-motion";
import { Skeleton } from "@/components/ui/skeleton";

// Dynamically load all PNGs from the achievements assets folder
const achievementImages = import.meta.glob<{ default: string }>(
  "../assets/achievements/*.png",
  { eager: true }
);

function getImgSrc(filename: string): string {
  const key = `../assets/achievements/${filename}`;
  return achievementImages[key]?.default ?? "";
}

const lockedSrc = getImgSrc("locked.png");

// Custom display order overrides per group
const GROUP_ORDER: Partial<Record<AchievementGroup, string[]>> = {
  Exploration: ["wanderer", "road_trip", "home_turf", "bar_regular", "dance_passport"],
  Variety: ["variety_pack", "collector", "encore", "crowd_favorite", "human_jukebox"],
};

function getGroupDefs(group: AchievementGroup) {
  const defs = ACHIEVEMENT_DEFS.filter(d => d.group === group);
  const order = GROUP_ORDER[group];
  if (!order) return defs;
  return order.map(id => defs.find(d => d.id === id)!).filter(Boolean);
}

const GROUP_COLORS: Record<AchievementGroup, string> = {
  Milestones:   "text-amber-600",
  Consistency:  "text-orange-500",
  Exploration:  "text-blue-500",
  Variety:      "text-purple-500",
  Social:       "text-pink-500",
  Hidden:       "text-slate-400",
};

const GROUP_BG: Record<AchievementGroup, string> = {
  Milestones:   "bg-amber-50 border-amber-200",
  Consistency:  "bg-orange-50 border-orange-200",
  Exploration:  "bg-blue-50 border-blue-200",
  Variety:      "bg-purple-50 border-purple-200",
  Social:       "bg-pink-50 border-pink-200",
  Hidden:       "bg-slate-50 border-slate-200",
};

interface BadgeProps {
  id: string;
  name: string;
  description: string;
  group: AchievementGroup;
  target: number;
  earned: boolean;
  progress: number;
  earnedAt?: string;
}

function AchievementBadge({ id, name, description, group, target, earned, progress, earnedAt }: BadgeProps) {
  const isHidden = group === "Hidden";
  const showDetails = earned || !isHidden;
  const imgSrc = earned ? getImgSrc(`${id}.png`) : lockedSrc;
  const showProgress = !earned && target > 1;

  return (
    <motion.div
      initial={{ opacity: 0, y: 10 }}
      animate={{ opacity: 1, y: 0 }}
      className="flex flex-col items-center gap-2 text-center"
      data-testid={`achievement-badge-${id}`}
    >
      {/* Badge circle */}
      <div className={`relative w-20 h-20 rounded-full flex items-center justify-center border-2 transition-all duration-300 ${
        earned
          ? "border-amber-400 shadow-md shadow-amber-100"
          : "border-border bg-secondary/30"
      }`}>
        {imgSrc ? (
          <img
            src={imgSrc}
            alt={showDetails ? name : "???"}
            className={`w-full h-full rounded-full object-cover ${earned ? "" : "opacity-60 grayscale"}`}
            onError={(e) => {
              if (lockedSrc) e.currentTarget.src = lockedSrc;
              else e.currentTarget.style.display = "none";
            }}
          />
        ) : (
          <Lock className="w-8 h-8 text-muted-foreground/40" />
        )}
        {earned && (
          <div className="absolute -bottom-1 -right-1 w-5 h-5 bg-amber-400 rounded-full flex items-center justify-center border-2 border-background">
            <span className="text-[8px] text-white font-bold">✓</span>
          </div>
        )}
      </div>

      {/* Name */}
      <p className={`text-xs font-semibold leading-tight max-w-[5rem] ${earned ? "text-foreground" : "text-muted-foreground"}`}>
        {showDetails ? name : "???"}
      </p>

      {/* Description — tooltip on tap (shown as small text) */}
      {showDetails && (
        <p className="text-[10px] text-muted-foreground leading-tight max-w-[5.5rem]">
          {description}
        </p>
      )}

      {/* Progress bar for multi-step unearned achievements */}
      {showProgress && (
        <div className="w-16 space-y-0.5">
          <div className="h-1.5 bg-secondary rounded-full overflow-hidden">
            <div
              className="h-full bg-primary/60 rounded-full transition-all"
              style={{ width: `${Math.min(100, (progress / target) * 100)}%` }}
            />
          </div>
          <p className="text-[9px] text-muted-foreground">{progress}/{target}</p>
        </div>
      )}

      {/* Earned date */}
      {earned && earnedAt && (
        <p className="text-[9px] text-muted-foreground">
          {new Date(earnedAt).toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" })}
        </p>
      )}
    </motion.div>
  );
}

export default function Achievements() {
  const [, setLocation] = useLocation();
  const { data: statuses, isLoading } = useAchievements();

  const statusMap = new Map(statuses?.map(s => [s.id, s]) ?? []);

  return (
    <div className="container px-4 pb-28 pt-8 mx-auto max-w-xl">
      {/* Header */}
      <div className="flex items-center justify-between mb-8">
        <h1 className="text-3xl font-display font-bold">Achievements</h1>
        <Button
          variant="ghost"
          className="text-muted-foreground hover:text-foreground gap-2"
          onClick={() => setLocation("/")}
          data-testid="button-back-home"
        >
          <ArrowLeft className="w-4 h-4" />
          Home
        </Button>
      </div>

      {isLoading ? (
        <div className="space-y-8">
          {[1, 2, 3].map(i => (
            <div key={i} className="space-y-4">
              <Skeleton className="h-6 w-32 rounded-lg" />
              <div className="grid grid-cols-3 gap-6">
                {[1, 2, 3].map(j => <Skeleton key={j} className="h-28 rounded-2xl" />)}
              </div>
            </div>
          ))}
        </div>
      ) : (
        <div className="space-y-8">
          {ACHIEVEMENT_GROUPS.map(group => {
            const defs = getGroupDefs(group);
            const groupStatuses = defs.map(d => statusMap.get(d.id));
            const earnedCount = groupStatuses.filter(s => s?.earned).length;

            return (
              <section key={group} className={`rounded-2xl border p-5 ${GROUP_BG[group]}`}>
                {/* Group header */}
                <div className="flex items-center justify-between mb-5">
                  <h2 className={`text-lg font-display font-bold ${GROUP_COLORS[group]}`}>
                    {group}
                  </h2>
                  <span className="text-xs text-muted-foreground font-medium bg-background/60 px-2 py-1 rounded-full border">
                    {earnedCount} / {defs.length}
                  </span>
                </div>

                {/* Badge grid */}
                <div className="grid grid-cols-3 gap-x-4 gap-y-6 justify-items-center">
                  {defs.map(def => {
                    const status = statusMap.get(def.id);
                    return (
                      <AchievementBadge
                        key={def.id}
                        id={def.id}
                        name={def.name}
                        description={def.description}
                        group={def.group}
                        target={def.target}
                        earned={status?.earned ?? false}
                        progress={status?.progress ?? 0}
                        earnedAt={status?.earnedAt}
                      />
                    );
                  })}
                </div>
              </section>
            );
          })}
        </div>
      )}
    </div>
  );
}

